import { format } from 'date-fns';
import { es } from 'date-fns/locale';
import ExcelJS from 'exceljs';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';
import type { Order } from '@/types/orders';

export type ExportFormat = 'csv' | 'pdf' | 'xlsx' | 'json';

export interface ExportOptions {
    format: ExportFormat;
    fields: string[];
    dateRange?: { from: Date | undefined; to: Date | undefined };
    orders: Order[];
}

const statusLabels: Record<string, string> = {
    'open': 'Abierto',
    'paid': 'Pagado',
    'cancelled': 'Cancelado',
    'refunded': 'Reembolsado'
};

const formatEuro = (amount: number) => {
    return new Intl.NumberFormat('es-ES', { style: 'currency', currency: 'EUR' }).format(amount);
};

const formatTime = (timestamp: number) => {
    return format(new Date(timestamp), 'dd/MM/yyyy HH:mm', { locale: es });
};

// Map selected field IDs to their display names and extractors
const fieldConfig: Record<string, { label: string, getValue: (order: Order) => string | number }> = {
    'order': { label: 'Número de Orden', getValue: (o) => o.orderNumber },
    'name': { label: 'Cliente', getValue: (o) => o.customerName || o.staffName || '-' },
    'table': { label: 'Mesa', getValue: (o) => o.tableLabel ? `${o.tableLabel}${o.environmentName ? ` (${o.environmentName})` : ''}` : '-' },
    'time': { label: 'Hora', getValue: (o) => formatTime(o.createdAt) },
    'total': { label: 'Total', getValue: (o) => o.totalAmount },
    'status': { label: 'Estado', getValue: (o) => statusLabels[o.status] || o.status },
    'items': { label: 'Productos', getValue: (o) => '-' } // Items aren't fully detailed in the Order type without fetching OrderDetails, so we just put a placeholder or omit if not possible.
};

export const exportOrdersData = async ({ format: exportFormat, fields, orders }: ExportOptions) => {
    if (!orders || orders.length === 0) return;

    // Filter configuration to only include selected fields
    const selectedConfigs = fields.map(field => fieldConfig[field]).filter(Boolean);
    
    const headers = selectedConfigs.map(c => c.label);
    const data = orders.map(order => selectedConfigs.map(c => c.getValue(order)));

    const timestamp = format(new Date(), 'yyyyMMdd_HHmmss');
    const filename = `comandas_export_${timestamp}`;

    switch (exportFormat) {
        case 'csv':
            exportToCSV(headers, data, filename);
            break;
        case 'xlsx':
            await exportToExcel(headers, data, filename);
            break;
        case 'pdf':
            exportToPDF(headers, data, filename);
            break;
        case 'json':
            exportToJSON(orders, fields, filename);
            break;
    }
};

const exportToCSV = (headers: string[], data: any[][], filename: string) => {
    const csvContent = [
        headers.join(','),
        ...data.map(row => row.map(val => {
            const strVal = String(val);
            // Escape quotes and wrap in quotes if contains comma
            if (strVal.includes(',') || strVal.includes('"')) {
                return `"${strVal.replace(/"/g, '""')}"`;
            }
            return strVal;
        }).join(','))
    ].join('\n');

    downloadBlob(new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' }), `${filename}.csv`);
};

const exportToExcel = async (headers: string[], data: any[][], filename: string) => {
    const workbook = new ExcelJS.Workbook();
    const worksheet = workbook.addWorksheet('Comandas');

    // Add headers
    worksheet.addRow(headers);
    
    // Style headers
    worksheet.getRow(1).font = { bold: true };
    worksheet.getRow(1).fill = {
        type: 'pattern',
        pattern: 'solid',
        fgColor: { argb: 'FFE0E0E0' }
    };

    // Add data
    data.forEach(row => {
        worksheet.addRow(row);
    });

    // Auto-fit columns
    worksheet.columns.forEach(column => {
        let maxLength = 0;
        column.eachCell?.({ includeEmpty: true }, cell => {
            const columnLength = cell.value ? cell.value.toString().length : 10;
            if (columnLength > maxLength) {
                maxLength = columnLength;
            }
        });
        column.width = maxLength < 10 ? 10 : maxLength + 2;
    });

    const buffer = await workbook.xlsx.writeBuffer();
    downloadBlob(new Blob([buffer], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' }), `${filename}.xlsx`);
};

const exportToPDF = (headers: string[], data: any[][], filename: string) => {
    const doc = new jsPDF();
    
    // Format data for PDF (format numbers as currency if they are totals)
    const pdfData = data.map(row => 
        row.map((val, index) => {
            if (headers[index] === 'Total' && typeof val === 'number') {
                return formatEuro(val);
            }
            return String(val);
        })
    );

    doc.setFontSize(16);
    doc.text('Historial de Comandas', 14, 15);
    doc.setFontSize(10);
    doc.text(`Fecha de exportación: ${format(new Date(), 'dd/MM/yyyy HH:mm')}`, 14, 22);

    autoTable(doc, {
        head: [headers],
        body: pdfData,
        startY: 25,
        theme: 'grid',
        styles: { fontSize: 8 },
        headStyles: { fillColor: [41, 128, 185] },
    });

    doc.save(`${filename}.pdf`);
};

const exportToJSON = (orders: Order[], fields: string[], filename: string) => {
    const dataToExport = orders.map(order => {
        const obj: Record<string, any> = {};
        fields.forEach(field => {
            if (fieldConfig[field]) {
                const val = fieldConfig[field].getValue(order);
                obj[fieldConfig[field].label] = val;
            }
        });
        return obj;
    });

    const jsonContent = JSON.stringify(dataToExport, null, 2);
    downloadBlob(new Blob([jsonContent], { type: 'application/json' }), `${filename}.json`);
};

const downloadBlob = (blob: Blob, filename: string) => {
    const link = document.createElement('a');
    if (link.download !== undefined) {
        const url = URL.createObjectURL(blob);
        link.setAttribute('href', url);
        link.setAttribute('download', filename);
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    }
};
